Define a schema for the request body and validate it using `zod` for improved type safety and validation. This aligns with the PR description's mention of 'JSON validation'.

```typescript
import { z } from 'zod';

const revalidationBodySchema = z.object({
  type: z.string(),
  date: z.string().optional(),
});

  const jsonBody = await req.json().catch(() => null);

  if (!jsonBody) {
    return NextResponse.json({ message: "Invalid JSON" }, { status: 400, headers });
  }

  const parsedBody = revalidationBodySchema.safeParse(jsonBody);

  if (!parsedBody.success) {
    return NextResponse.json({ message: "Invalid request body", errors: parsedBody.error.format() }, { status: 400, headers });
  }

  const { type, date } = parsedBody.data;
```

